args.sparql:
SELECT DISTINCT ?country ?countryLabel ?servicePercent
WHERE {
  # Get DR Congo
  wd:Q974 p:P2297/psv:P193 wd:Q55638;
            p:P2297/ps:P2297 ?servicePercent.
  wd:Q974 wdt:P31 wd:Q6256.
  SERVICE wikidata:label { bd:serviceParam wikibase:language "en". }

  UNION

  # Get neighbors
  wd:Q974 wdt:P47 ?neighbor.
  ?neighbor p:P2297/psv:P193 wd:Q55638;
             p:P2297/ps:P2297 ?servicePercent.
  ?neighbor wdt:P31 wd:Q6256.
  SERVICE wikidata:label { bd:serviceParam wikibase:language "en". }
}

SELECT DISTINCT ?country ?countryLabel ?servicePercent
WHERE {
  {
    wd:Q974 wdt:P31 wd:Q6256.
    wd:Q974 p:P2297 ?statement.
    ?statement ps:P2297 wd:Q55638.
    ?statement psv:P2297 ?servicePercent.
    BIND(wd:Q974 AS ?country)
    SERVICE wikidata:label { bd:serviceParam wikibase:language "en" }
  }
  UNION
  {
    wd:Q974 wdt:P47 ?neighbor.
    ?neighbor wdt:P31 wd:Q6256.
    ?neighbor p:P2297 ?neighborStatement.
    ?neighborStatement ps:P2297 wd:Q55638.
    ?neighborStatement psv:P2297 ?servicePercent.
    BIND(?neighbor AS ?country)
    SERVICE wikidata:label { bd:serviceParam wikibase:language "en" }
  }
}
